const fs = require('fs');
const path = require('path');
const rowsJson = $fromAI('rowsJson','空值行 JSON（可传 emptyRows 数组，或包含 emptyRows 字段的对象）','string');
const destinationRoot = $fromAI('destinationRoot','目标根目录绝对路径','string');
const sourceRootsRaw = $fromAI('sourceRoots','可选：源根目录列表，逗号分隔，用于保持相对结构','string') || '';
const pathMappingsJson = $fromAI('pathMappingsJson','可选：盘符映射 JSON，例如 {\"Z:\":\"/home/zkzy/16T/common\"}','string') || '{}';
const approvalTextRaw = $fromAI('approvalText','用户审批文本（确认执行拷贝/批准执行拷贝/approve copy）','string') || '';
function parseRows(raw){const p=JSON.parse(raw);if(Array.isArray(p))return p;if(p&&Array.isArray(p.emptyRows))return p.emptyRows;if(p&&Array.isArray(p.data?.emptyRows))return p.data.emptyRows;throw new Error('rowsJson 无法解析为空值行数组');}
function parseMappings(raw){try{const o=JSON.parse(raw||'{}');return o&&typeof o==='object'?o:{};}catch{return {};}}
function normalizePath(v,m){if(!v||typeof v!=='string')return '';let s=v.trim();if(!s)return '';s=s.replace(/\\/g,'/');const mm=s.match(/^([A-Za-z]:)(\/.*)?$/);if(mm){const d=mm[1],r=mm[2]||'';if(m[d])return path.join(m[d],r).replace(/\\/g,'/');}return s;}
function isDir(p){try{return fs.existsSync(p)&&fs.statSync(p).isDirectory();}catch{return false;}}
function approved(text){const t=String(text||'').toLowerCase();return t.includes('确认执行拷贝')||t.includes('批准执行拷贝')||t.includes('approve copy');}
const rows=parseRows(rowsJson);
const mappings=parseMappings(pathMappingsJson);
const sourceRoots=sourceRootsRaw.split(',').map(s=>normalizePath(s,mappings)).filter(Boolean);
if(!destinationRoot)throw new Error('缺少 destinationRoot');
const plan=[];
for(const row of rows){
  const folderName=String(row['文件夹名称']||'').trim();
  const filePathRaw=String(row['文件路径']||'').trim();
  const filePath=normalizePath(filePathRaw,mappings);
  const candidates=[];
  if(filePath){
    candidates.push(filePath);
    if(folderName)candidates.push(path.join(filePath,folderName));
  }
  let src=candidates.find(isDir)||'';
  if(!src&&folderName){
    for(const root of sourceRoots){
      const c=path.join(root,folderName);
      if(isDir(c)){src=c;break;}
    }
  }
  if(!src){
    plan.push({ok:false,folderName,filePath:filePathRaw,reason:'未找到可用源目录'});
    continue;
  }
  let dest=path.join(destinationRoot,path.basename(src));
  for(const root of sourceRoots){
    const rel=path.relative(root,src);
    if(!rel.startsWith('..')&&!path.isAbsolute(rel)){dest=path.join(destinationRoot,rel);break;}
  }
  plan.push({ok:true,folderName,filePath:filePathRaw,sourceFolder:src,destinationFolder:dest});
}
if(!approved(approvalTextRaw)){
  return [{json:{ok:true,executed:false,approvalRequired:true,approvalHint:'请点击人机交互按钮同意，或回复“确认执行拷贝”',total:rows.length,copyable:plan.filter(p=>p.ok).length,failed:plan.filter(p=>!p.ok).length,planPreview:plan.slice(0,20)}}];
}
fs.mkdirSync(destinationRoot,{recursive:true});
const results=[];
for(const item of plan){
  if(!item.ok){results.push({ok:false,folderName:item.folderName||'',reason:item.reason||'计划项不可执行'});continue;}
  try{
    fs.mkdirSync(path.dirname(item.destinationFolder),{recursive:true});
    fs.cpSync(item.sourceFolder,item.destinationFolder,{recursive:true,force:false,errorOnExist:false});
    results.push({ok:true,folderName:item.folderName||'',sourceFolder:item.sourceFolder,destinationFolder:item.destinationFolder});
  }catch(error){
    results.push({ok:false,folderName:item.folderName||'',sourceFolder:item.sourceFolder,destinationFolder:item.destinationFolder,reason:error.message});
  }
}
return [{json:{ok:true,executed:true,approvalRequired:false,total:rows.length,copied:results.filter(r=>r.ok).length,failed:results.filter(r=>!r.ok).length,results}}];
